@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput"></textarea>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;
    private System.Timers.Timer? autoSaveTimer;
    private IJSObjectReference? jsModule;

    private bool HasUnsavedChanges => content != savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        jsModule = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/Pages/Notepad.razor.js");

        var restored = await jsModule.InvokeAsync<string?>("load");
        if (restored is not null)
        {
            content = restored;
            savedContent = restored;
            StateHasChanged();
        }

        await jsModule.InvokeVoidAsync("enableBeforeUnload");

        autoSaveTimer = new System.Timers.Timer(30_000);
        autoSaveTimer.Elapsed += async (_, _) => await InvokeAsync(AutoSaveAsync);
        autoSaveTimer.Start();
    }

    private async Task AutoSaveAsync()
    {
        if (!HasUnsavedChanges || jsModule is null) return;
        await SaveAsync();
    }

    private async Task SaveNowAsync()
    {
        if (jsModule is null) return;
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        await jsModule!.InvokeVoidAsync("save", content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
        StateHasChanged();
    }

    private async Task ClearAsync()
    {
        if (jsModule is null) return;
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;
        await jsModule.InvokeVoidAsync("clear");
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Stop();
        autoSaveTimer?.Dispose();

        if (jsModule is not null)
        {
            // Save any pending changes before leaving
            if (HasUnsavedChanges)
            {
                await jsModule.InvokeVoidAsync("save", content);
            }
            await jsModule.InvokeVoidAsync("disableBeforeUnload");
            await jsModule.DisposeAsync();
        }
    }
}

const STORAGE_KEY = "notepad-content";

let beforeUnloadHandler = null;

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
}

export function load() {
    return localStorage.getItem(STORAGE_KEY);
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
}

export function enableBeforeUnload() {
    beforeUnloadHandler = (e) => {
        e.preventDefault();
    };
    window.addEventListener("beforeunload", beforeUnloadHandler);
}

export function disableBeforeUnload() {
    if (beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

